/**
 * @param {number[][]} matrix
 * @return {number[]}
 */
function solve(matrix) {
    const n = matrix.length;
    const ans = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        let degree = 0;
        // The degree of vertex i is the sum of the i-th row (or i-th column, due to symmetry)
        for (let j = 0; j < n; j++) {
            if (matrix[i][j] === 1) {
                degree++;
            }
        }
        ans[i] = degree;
    }

    return ans;
}
